ustom_text_5_rotate:{label:"Testo 5: Rotazione (°)",helper:"Angolo di rotazione per Testo 5 (-180..180)."},custom_text_5_skew_x:{label:"Testo 5: Inclinazione X (°)",helper:"Angolo di inclinazione (skew) sull’asse X (-60..60)."},custom_text_5_skew_y:{label:"Testo 5: Inclinazione Y (°)",helper:"Angolo di inclinazione (skew) sull’asse Y (-60..60)."},custom_text_decimals:{label:"Decimali",helper:"Slot Testo personalizzato: Auto (-1) usa la precisione Home Assistant (suggested_display_precision, altrimenti step per input_number). 0–10 forza le cifre decimali. Anche i popup usano la stessa logica automatica."},car_pct_color:{label:"Colore SOC auto",helper:"Colore esadecimale per il testo SOC EV (es. #00FFFF)."},car2_pct_color:{label:"Colore SOC Auto 2",helper:"Colore esadecimale per il testo SOC della seconda EV (usa Car SOC se vuoto)."},car1_name_color:{label:"Colore nome Auto 1",helper:"Colore applicato all etichetta del nome Auto 1."},car2_name_color:{label:"Colore nome Auto 2",helper:"Colore applicato all etichetta del nome Auto 2."},car1_color:{label:"Colore Auto 1",helper:"Colore applicato al valore potenza Auto 1."},car2_color:{label:"Colore Auto 2",helper:"Colore applicato al valore potenza Auto 2."},car_text_color:{label:"Colore testo auto",helper:"Colore predefinito per entrambe le auto (etichetta e potenza). Sostituito da Colore testo Auto 1/2 se impostati."},car1_text_color:{label:"Colore testo Auto 1",helper:"Colore per etichetta e potenza Auto 1. Vuoto = usa Colore testo auto."},car2_text_color:{label:"Colore testo Auto 2",helper:"Colore per etichetta e potenza Auto 2. Vuoto = usa Colore testo auto."},night_mode_enabled:{label:"Abilita sfondo giorno/notte",helper:"Cambia sfondo automaticamente con sun.sun (below_horizon = notte)."},background_image_night:{label:"URL immagine sfondo notte",helper:"Usa /local/community/lumina-energy-card/night.jpg o night.png. Il file deve essere in www/community/lumina-energy-card/ e chiamarsi solo night.jpg o night.png. Dopo aver aggiunto il file, ricarica l'integrazione e aggiorna la pagina."},sensor_sun_entity:{label:"Entità sole",helper:"Entità sun (es. sun.sun). Quando lo stato è below_horizon si mostra l'immagine notte."},night_mode_override:{label:"Forza vista notte",helper:"Toggle per mostrare subito lo sfondo notte (per test)."},pro_password:{label:"Password PRO",helper:"⚠️ FUNZIONE PRO: Questa è una funzione premium."},pro_password_by_user_title:"Più account HA, più password PRO (opzionale)",pro_password_by_user:{label:"Mappa (id utente → password)",helper:"Serve solo se più login Home Assistant condividono questa stessa dashboard/card e ognuno ha una password PRO diversa.\n\nCome funziona: ogni CHIAVE è l'id utente HA. ogni VALORE è la password PRO di quella persona. Chi è loggato usa prima la sua riga; se non c'è, vale il campo password singolo sopra.\n\nDove trovare l'id utente: Impostazioni → Persone → Utenti — aprite il nome dell'utente; in alto compare l'id.\n\nLicenze: ognuno deve avere comunque licenza/hash valido sul server — qui memorizzi solo più password nella stessa config. Lascia vuoto se usi un solo utente HA."},license_status:"Stato licenza",license_active:"PRO attivo",license_inactive:"Non attivo",pro_unlocked:"✓ Funzioni PRO sbloccate",paypal_button:"Sblocca Funzioni PRO (5€)",paypal_note:"IMPORTANTE: Puoi pagare con PayPal (SOLO DONAZIONE, NON beni e servizi) oppure con GitHub Sponsors. Sistema automatico: se non trova corrispondenza, la password NON verrà inviata. Dopo il pagamento richiedi la licenza PRO qui sotto e seleziona il metodo corretto (PayPal / GitHub).",unlock_pro_features:"Sblocca Funzioni PRO",pro_hero_active:"PRO gia attivo",pro_hero_unlock:"Sblocca Lumina PRO in 1 minuto - 5EUR",pro_hero_desc:"Overlay immagini, popup avanzati, flow personalizzati e strumenti drag and drop PRO. Ogni licenza è legata a un utente Home Assistant. Più utenti possono usare la stessa card: serve una licenza e una password per persona; in Licenza e pagamento imposta la tabella utente → password (pro_password_by_user).",pro_hero_discover:"Scopri funzioni PRO",pro_hero_pay:"PayPal — 5€",pro_hero_pay_github:"GitHub — 5€",pro_welcome_title:"Lumina PRO - Sblocca con 5EUR",pro_welcome_badge:"UNA VOLTA",pro_welcome_desc:"Sblocca tutte le funzioni avanzate e personalizza la card in modo totale. Pagamento consigliato: 5EUR via PayPal (donazione) o GitHub Sponsors.",pro_welcome_feat_1:"Overlay immagini personalizzate (fino a 5) con posizionamento libero",pro_welcome_feat_2:"Custom flow, custom popup (Classico / Tactical / Life Sign), custom text",pro_welcome_feat_3:"Background personale, editor drag and drop avanzato, strumenti PRO",pro_welcome_feat_4:"Piu opzioni visuali, layout e controllo dettagliato della UI",pro_welcome_feat_5:"Mini Cam: stream telecamera sulla mappa, con etichetta e posizione",pro_welcome_feat_6:"Popup personalizzati: stili avanzati (Classico, Tactical, Life Sign, …)",pro_welcome_feat_7:"Sezione persone: aggiungi e mostra le “person” / persone in card",pro_welcome_feat_8:"Previsione solare: servizio previsione produzione e HUD sulla card",pro_welcome_close:"Ho capito",pro_welcome_after_note:"Dopo il pagamento usa il form sottostante per richiedere la password PRO.",pro_welcome_paypal:"PayPal 5EUR",pro_welcome_github:"GitHub Sponsors",activate:"Attiva",checking:"Verifica...",request_pro_license:"Richiedi Licenza PRO",your_email:"La tua email",payment_method:"Metodo pagamento (PayPal / GitHub / Colletta)",payment_method_paypal:"PayPal (donazione)",payment_method_github:"GitHub Sponsors",paypal_payment_email:"Email di pagamento PayPal",paypal_first_name:"Nome PayPal",paypal_last_name:"Cognome PayPal",github_username:"Username GitHub",paypal_transaction_id:"ID Transazione PayPal",send_request:"Invia richiesta",request_sent:"Richiesta inviata! Riceverai la licenza via email.",request_error:"Errore durante l’invio. Riprova.",network_error:"Impossibile contattare il server. Controlla la connessione e riprova.",existing_u